// Authenticate and get session
const session = await OdooService.authenticate()
console.log(`Logged in as ${session.name}`)

// Check authentication status
if (OdooService.isAuthenticated()) {
  console.log('User:', OdooService.getSession().name)
}

// Logout
OdooService.logout()

// Subscribe to auth changes
const unsubscribe = OdooService.onAuthChange((session) => {
  console.log(session ? 'Logged in' : 'Logged out')
})

// Create
const id = await OdooService.create('res.partner', {
  name: 'New Partner',
  email: 'partner@example.com',
})

// Read specific records
const records = await OdooService.read('res.partner', [id], ['name', 'email'])

// Update
await OdooService.write('res.partner', [id], { name: 'Updated Name' })

// Delete
await OdooService.unlink('res.partner', [id])

// Count matching records
const total = await OdooService.searchCount('res.partner', [['is_company', '=', true]])

// List available databases
const databases = await OdooService.listDatabases()

// Get server version info
const version = await OdooService.versionInfo()
console.log(version.server_version)  // e.g. "17.0"
